@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ConduitIDE() {
    val context = LocalContext.current
    val drawerState = rememberDrawerState(initialValue = DrawerValue.Closed)
    val scope = rememberCoroutineScope()
    var currentView by remember { mutableStateOf("chat") }
    var selectedTab by remember { mutableIntStateOf(0) }

    var chatMessages by remember { mutableStateOf(listOf(Message(0, "AI", "Hello! I am your AI File Manager. Tell me what to do with your files.", true))) }
    var chatInput by remember { mutableStateOf("") }
    var manualCode by remember { mutableStateOf("import os\nprint('Current Directory:', os.getcwd())\nprint('Files:', os.listdir('.'))") }
    var consoleOutput by remember { mutableStateOf("Console ready...") }

    var sessions by remember { mutableStateOf(listOf<Pair<String, String>>()) }
    var currentSessionId by remember { mutableStateOf<String?>(null) }
    var isAiThinking by remember { mutableStateOf(false) }
    var isDataLoading by remember { mutableStateOf(false) }
    var currentCwd by remember { mutableStateOf("/storage/emulated/0") }

    val python = Python.getInstance()
    val executor = python.getModule("executor")

    val filePickerLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.GetContent()
    ) { uri ->
        uri?.let {
            scope.launch(Dispatchers.IO) {
                isDataLoading = true
                try {
                    val contentResolver = context.contentResolver
                    val fileName = "attached_" + (System.currentTimeMillis() % 10000) + "_" + (uri.path?.split("/")?.lastOrNull() ?: "file")
                    val destDir = File("/storage/emulated/0/Conduit")
                    if (!destDir.exists()) destDir.mkdirs()

                    val destFile = File(destDir, fileName)
                    contentResolver.openInputStream(uri)?.use { input ->
                        FileOutputStream(destFile).use { output ->
                            input.copyTo(output)
                        }
                    }

                    withContext(Dispatchers.Main) {
                        val attachmentText = "Context: I have attached a file named '$fileName' to my workspace at '${destFile.absolutePath}'. Please analyze its content if needed."
                        chatInput = attachmentText
                        Toast.makeText(context, "File attached to workspace", Toast.LENGTH_SHORT).show()
                    }
                } catch (e: Exception) {
                    withContext(Dispatchers.Main) {
                        Toast.makeText(context, "Upload failed: ${e.message}", Toast.LENGTH_LONG).show()
                    }
                }
                isDataLoading = false
            }
        }
    }
    val pipManager = python.getModule("pip_manager")
    val terminalManager = python.getModule("terminal_manager")

    var terminalOutput by remember { mutableStateOf("Python ${System.getProperty("os.version")} REPL\n>>> ") }
    var terminalInput by remember { mutableStateOf("") }

    val onNewChat = remember { 
        { 
            scope.launch {
                isDataLoading = true
                val newId = SupabaseClient.createNewSessionInSupabase()
                if (newId != null) {
                    sessions = SupabaseClient.fetchSessionsFromSupabase()
                    currentSessionId = newId
                    chatMessages = emptyList()
                    Toast.makeText(context, "New session created", Toast.LENGTH_SHORT).show()
                    drawerState.close()
                } else {
                    Toast.makeText(context, "Failed to create session", Toast.LENGTH_SHORT).show()
                }
                isDataLoading = false
            }
        } 
    }

    val sendInternal = remember(currentSessionId) { 
        { text: String, displayAsSystem: Boolean -> 
            if (text.isNotBlank()) {
                scope.launch {
                    isAiThinking = true
                    if (currentSessionId == null) {
                        val newId = SupabaseClient.createNewSessionInSupabase()
                        currentSessionId = newId
                        sessions = SupabaseClient.fetchSessionsFromSupabase()
                    }

                    val userMsg = Message(System.currentTimeMillis(), "User", if (displayAsSystem) "[File Structure Context Injected]" else text, false, isSystemAction = displayAsSystem)
                    chatMessages = chatMessages + userMsg

                    val aiResponse = SupabaseClient.callGeminiEdgeFunction(text, currentSessionId)
                    chatMessages = chatMessages + Message(System.currentTimeMillis() + 1, "AI", aiResponse, true)

                    currentCwd = withContext(Dispatchers.IO) {
                        try { python.getModule("os").callAttr("getcwd").toString() } catch(e: Exception) { currentCwd }
                    }
                    isAiThinking = false
                }
            }
        }
    }

    val onSend = { 
        if (chatInput.isNotBlank()) {
            val input = chatInput
            chatInput = ""
            sendInternal(input, false)
        }
    }

    LaunchedEffect(Unit) {
        scope.launch {
            isDataLoading = true
            sessions = SupabaseClient.fetchSessionsFromSupabase()
            isDataLoading = false
        }
    }

    ModalNavigationDrawer(
        drawerState = drawerState,
        drawerContent = {
            ModalDrawerSheet(
                modifier = Modifier.fillMaxWidth(0.8f) // Only covers 80% of width
            ) {
                SidebarContent(
                    sessions = sessions,
                    onSessionClick = { id -> 
                        currentSessionId = id
                        scope.launch {
                            isDataLoading = true
                            chatMessages = SupabaseClient.fetchHistoryForSession(id)
                            isDataLoading = false
                            drawerState.close()
                        }
                    },
                    onNewChatClick = { onNewChat() },
                    onDeleteClick = { id ->
                        scope.launch {
                            isDataLoading = true
                            if (SupabaseClient.deleteSessionFromSupabase(id)) {
                                sessions = SupabaseClient.fetchSessionsFromSupabase()
                                if (currentSessionId == id) {
                                    currentSessionId = null
                                    chatMessages = listOf(Message(0, "AI", "Session deleted. Start a new one!", true))
                                }
                                Toast.makeText(context, "Session deleted", Toast.LENGTH_SHORT).show()
                            }
                            isDataLoading = false
                        }
                    },
                    onPipClick = { currentView = "pip"; scope.launch { drawerState.close() } },
                    onTerminalClick = { currentView = "terminal"; scope.launch { drawerState.close() } },
                    onInterpreterClick = { currentView = "interpreter"; scope.launch { drawerState.close() } },
                    onResetInterpreter = {
                        scope.launch(Dispatchers.IO) {
                            val res = executor.callAttr("reset_state").toString()
                            currentCwd = "/storage/emulated/0"
                            withContext(Dispatchers.Main) {
                                Toast.makeText(context, res, Toast.LENGTH_SHORT).show()
                                drawerState.close()
                            }
                        }
                    },
                    onChatNavClick = { currentView = "main"; selectedTab = 0; scope.launch { drawerState.close() } }
                )
            }
        }
    ) {
        Scaffold(
            topBar = {
                TopAppBar(
                    title = {
                        Column {
                            Text("Conduit AI", style = MaterialTheme.typography.titleMedium)
                            Text(currentCwd, style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.primary)
                        }
                    },
                    navigationIcon = {
                        IconButton(onClick = { scope.launch { drawerState.open() } }) {
                            Icon(Icons.Default.Menu, "Menu")
                        }
                    },
                    actions = {
                        if (currentView == "chat" || currentView == "main") {
                            IconButton(onClick = { onNewChat() }) {
                                Icon(Icons.Default.AddComment, contentDescription = "New Chat", tint = MaterialTheme.colorScheme.primary)
                            }
                        }
                    }
                )
            },
            bottomBar = {
                if (currentView == "chat" || currentView == "main") {
                    TabRow(selectedTabIndex = selectedTab) {
                        Tab(selected = selectedTab == 0, onClick = { selectedTab = 0 }, text = { Text("AI Chat") })
                        Tab(selected = selectedTab == 1, onClick = { selectedTab = 1 }, text = { Text("Manual") })
                    }
                }
            }
        ) { padding ->
            Box(modifier = Modifier.padding(padding)) {
                if (isDataLoading) {
                    LinearProgressIndicator(
                        modifier = Modifier.fillMaxWidth().zIndex(1f),
                        color = MaterialTheme.colorScheme.primary,
                        trackColor = Color.Transparent
                    )
                }
                when (currentView) {
                    "terminal" -> TerminalScreen(
                        input = terminalInput,
                        output = terminalOutput,
                        onInputChange = { terminalInput = it },
                        onClear = { terminalOutput = "Python ${System.getProperty("os.version")} REPL\n>>> " },
                        onRun = {
                            if (terminalInput.isNotBlank()) {
                                val cmd = terminalInput
                                terminalInput = ""
                                scope.launch(Dispatchers.IO) {
                                    val result = terminalManager.callAttr("run_repl_line", cmd).toString()
                                    withContext(Dispatchers.Main) {
                                        terminalOutput += "$cmd\n$result${if (result.isEmpty()) "" else "\n"}>>> "
                                    }
                                }
                            }
                        }
                    )
                    "pip" -> PipManagerScreen()
                    "interpreter" -> InterpreterScreen()
                    else -> {
                        when (selectedTab) {
                            0 -> ChatScreen(
                                messages = chatMessages,
                                input = chatInput,
                                isThinking = isAiThinking,
                                onInputChange = { chatInput = it },
                                                                onSend = onSend,
                                onAttachFile = { filePickerLauncher.launch("*/*") },
                                onInjectStructure = { sendInternal(it, true) },
                                onQuickAction = { sendInternal(it, false) }
                            )
                            1 -> ManualScreen(
                                code = manualCode,
                                onCodeChange = { manualCode = it },
                                output = consoleOutput,
                                onRun = {
                                    scope.launch(Dispatchers.IO) {
                                        withContext(Dispatchers.Main) { consoleOutput = "Running..." }
                                        try {
                                            val result = executor.callAttr("run_code", manualCode).toString()
                                            withContext(Dispatchers.Main) { consoleOutput = result }
                                        } catch (e: Exception) {
                                            withContext(Dispatchers.Main) { consoleOutput = "Error: ${e.message}" }
                                        }
                                    }
                                }
                            )
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun SidebarContent(
    sessions: List<Pair<String, String>>, 
    onSessionClick: (String) -> Unit, 
    onNewChatClick: () -> Unit, 
    onDeleteClick: (String) -> Unit,
    onPipClick: () -> Unit,
    onTerminalClick: () -> Unit,
    onInterpreterClick: () -> Unit,
    onChatNavClick: () -> Unit,
    onResetInterpreter: () -> Unit
) {
    Column(modifier = Modifier.padding(16.dp).fillMaxHeight()) {
        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
            Text("Sessions", style = MaterialTheme.typography.titleMedium)
            IconButton(onClick = onNewChatClick) {
                Icon(Icons.Default.Add, contentDescription = "New Chat")
            }
        }

        HorizontalDivider(modifier = Modifier.padding(vertical = 8.dp))

        Text("Tools", style = MaterialTheme.typography.titleSmall, color = Color.Gray)
        NavigationDrawerItem(label = { Text("AI Chat") }, selected = false, onClick = onChatNavClick, icon = { Icon(Icons.Default.Chat, null) })
        NavigationDrawerItem(label = { Text("Pip Install") }, selected = false, onClick = onPipClick, icon = { Icon(Icons.Default.Download, null) })
        NavigationDrawerItem(label = { Text("Terminal") }, selected = false, onClick = onTerminalClick, icon = { Icon(Icons.Default.Terminal, null) })
        NavigationDrawerItem(label = { Text("Interpreter") }, selected = false, onClick = onInterpreterClick, icon = { Icon(Icons.Default.Settings, null) })
        NavigationDrawerItem(label = { Text("Reset Python") }, selected = false, onClick = onResetInterpreter, icon = { Icon(Icons.Default.Refresh, null) })

        HorizontalDivider(modifier = Modifier.padding(vertical = 16.dp))

        Text("History", style = MaterialTheme.typography.titleSmall, color = Color.Gray)
        LazyColumn {
            items(sessions) { session ->
                Row(modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                    NavigationDrawerItem(
                        modifier = Modifier.weight(1f),
                        label = { Text(session.second, maxLines = 1) }, 
                        selected = false, 
                        onClick = { onSessionClick(session.first) }, 
                        icon = { Icon(Icons.Default.History, null) }
                    )
                    IconButton(onClick = { onDeleteClick(session.first) }) {
                        Icon(Icons.Default.Delete, contentDescription = "Delete", tint = Color.Red.copy(alpha = 0.6f), modifier = Modifier.size(20.dp))
                    }
                }
            }
        }
    }
}

@Composable
fun ChatScreen(messages: List<Message>, input: String, isThinking: Boolean, onInputChange: (String) -> Unit, onSend: () -> Unit, onAttachFile: () -> Unit, onInjectStructure: (String) -> Unit, onQuickAction: (String) -> Unit) {
    val python = Python.getInstance()
    val executor = python.getModule("executor")
    val listState = rememberLazyListState()
    val scope = rememberCoroutineScope()

    val showScrollToBottom by remember {
        derivedStateOf { 
            listState.firstVisibleItemIndex > 2 || listState.canScrollForward
        }
    }

    LaunchedEffect(messages.size, isThinking) {
        if (messages.isNotEmpty() || isThinking) {
            listState.animateScrollToItem((messages.size + if (isThinking) 1 else 0))
        }
    }

    Column(modifier = Modifier.fillMaxSize()) {
        LazyRow(
            modifier = Modifier.fillMaxWidth().padding(horizontal = 8.dp, vertical = 4.dp),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            val actions = listOf("List Files", "Storage Info", "Recent Downloads", "Search PDFs")
            items(actions) { action ->
                AssistChip(
                    onClick = { onQuickAction(action) },
                    label = { Text(action, style = MaterialTheme.typography.labelSmall) },
                    colors = AssistChipDefaults.assistChipColors(labelColor = MaterialTheme.colorScheme.primary)
                )
            }
        }

        Box(modifier = Modifier.weight(1f)) {
                        LazyColumn(modifier = Modifier.fillMaxSize().padding(horizontal = 8.dp), state = listState) {
                items(messages) { msg -> 
                    ChatBubble(
                        sender = msg.sender, 
                        message = msg.text, 
                        isAi = msg.isAi, 
                        isSystem = msg.isSystemAction, 
                        onEdit = { onInputChange(it) }
                    ) 
                }
                if (isThinking) {
                    item {
                        Row(modifier = Modifier.padding(16.dp), verticalAlignment = Alignment.CenterVertically) {
                            CircularProgressIndicator(modifier = Modifier.size(16.dp), strokeWidth = 2.dp, color = MaterialTheme.colorScheme.primary)
                            Spacer(modifier = Modifier.width(8.dp))
                            Text("Conduit is thinking...", style = MaterialTheme.typography.labelSmall, color = Color.Gray)
                        }
                    }
                }
            }

            AnimatedVisibility(
                visible = showScrollToBottom,
                enter = fadeIn(),
                exit = fadeOut(),
                modifier = Modifier.align(Alignment.BottomCenter).padding(bottom = 16.dp)
            ) {
                FilledIconButton(
                    onClick = { scope.launch { listState.animateScrollToItem(messages.size) } },
                    colors = IconButtonDefaults.filledIconButtonColors(containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.9f)),
                    modifier = Modifier.size(40.dp).border(1.dp, Color.White.copy(alpha = 0.1f), RoundedCornerShape(20.dp))
                ) {
                    Icon(Icons.Default.ArrowDownward, contentDescription = "Scroll to bottom", modifier = Modifier.size(20.dp))
                }
            }
        }

        Surface(tonalElevation = 8.dp, shadowElevation = 8.dp) {
            Row(modifier = Modifier.padding(8.dp).imePadding(), verticalAlignment = Alignment.CenterVertically) {
                TextField(
                    value = input, 
                    onValueChange = onInputChange, 
                    modifier = Modifier.weight(1f),
                    keyboardOptions = KeyboardOptions(imeAction = ImeAction.Send),
                    keyboardActions = KeyboardActions(onSend = { onSend() }),
                    placeholder = { Text("Ask AI anything...") },
                    leadingIcon = {
                        Row {
                                                            IconButton(onClick = {
                                    val structure = try {
                                        executor.callAttr("get_structure").toString()
                                    } catch (e: Exception) { "Error scanning storage: ${e.message}" }
                                    onInjectStructure("Context Update - Current File Structure:\n---\n$structure\n---\nUpdate your internal model with this structure.")
                                }) {
                                Icon(Icons.Default.AccountTree, contentDescription = "Inject Structure", tint = MaterialTheme.colorScheme.primary)
                            }
                            IconButton(onClick = onAttachFile) {
                                Icon(Icons.Default.AttachFile, contentDescription = "Attach File", tint = MaterialTheme.colorScheme.primary)
                            }
                        }
                    }
                )
                IconButton(onClick = onSend) { Icon(Icons.Default.Send, null) }
            }
        }
    }
}

@Composable
fun ChatBubble(sender: String, message: String, isAi: Boolean, isSystem: Boolean = false, onEdit: (String) -> Unit = {}) {
    val context = LocalContext.current
    val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE) as ClipboardManager

    Column(
        modifier = Modifier.padding(vertical = 4.dp).fillMaxWidth(),
        horizontalAlignment = if (isAi) Alignment.Start else Alignment.End
    ) {
